  3→use tracing::{debug, trace, warn};
  4→
  5→use crate::{
  6→    http::{retry_after_ms_from_headers, with_retry_after_marker},
  7→    ollama::normalize_ollama_api_base_url,
  8→    openai_compat::{
  9→        parse_openai_compat_usage_from_payload, parse_tool_calls,
 10→        split_responses_instructions_and_input, strip_think_tags, to_openai_tools,
 11→        to_responses_api_tools,
 12→    },
 13→    raw_model_id,
 14→};
