 16→use moltis_agents::model::{ChatMessage, CompletionResponse, Usage};
 17→
 18→use super::OpenAiProvider;
 19→
 20→fn is_chat_endpoint_unsupported_model_error(body_text: &str) -> bool {
 21→    let lower = body_text.to_ascii_lowercase();
 22→    lower.contains("not a chat model")
 23→        || lower.contains("does not support chat")
 24→        || lower.contains("only supported in v1/responses")
 25→        || lower.contains("not supported in the v1/chat/completions endpoint")
 26→        || lower.contains("input content or output modality contain audio")
 27→        || lower.contains("requires audio")
 28→}
 29→
 30→fn should_warn_on_api_error(status: reqwest::StatusCode, body_text: &str) -> bool {
 31→    if is_chat_endpoint_unsupported_model_error(body_text) {
 32→        return false;
 33→    }
 34→    !matches!(status.as_u16(), 404)
 35→}
