 37→impl OpenAiProvider {
 38→    fn apply_probe_output_cap_chat(&self, body: &mut serde_json::Value) {
 39→        let raw = raw_model_id(&self.model).to_ascii_lowercase();
 40→        let capability = raw.rsplit('/').next().unwrap_or(raw.as_str());
 41→        let uses_max_completion_tokens = capability.starts_with("gpt-5")
 42→            || capability.starts_with("o1")
 43→            || capability.starts_with("o3")
 44→            || capability.starts_with("o4");
 45→        if uses_max_completion_tokens {
 46→            // GPT-5 and reasoning models need a higher minimum output cap.
 47→            // Values below ~10 can trigger 400 errors on some models.
 48→            body["max_completion_tokens"] = serde_json::json!(16);
 49→        } else {
 50→            body["max_tokens"] = serde_json::json!(1);
 51→        }
 52→    }
 53→
 54→    pub(super) async fn probe_chat_completions(&self) -> anyhow::Result<()> {
 55→        let messages = vec![ChatMessage::user("ping")];
 56→        let mut openai_messages = self.serialize_messages_for_request(&messages);
 57→        self.apply_openrouter_cache_control(&mut openai_messages);
 58→        let mut body = serde_json::json!({
 59→            "model": self.model,
 60→            "messages": openai_messages,
 61→        });
 62→        self.apply_system_prompt_rewrite(&mut body);
 63→        // Probes only answer "can this model respond at all?".
 64→        // Keep them cheap instead of mirroring full reasoning budgets.
 65→        self.apply_probe_output_cap_chat(&mut body);
 66→
 67→        debug!(model = %self.model, "openai probe request");
 68→        trace!(body = %serde_json::to_string(&body).unwrap_or_default(), "openai probe request body");
 69→
 70→        let http_resp = self
 71→            .client
 72→            .post(format!("{}/chat/completions", self.base_url))
 73→            .header(
 74→                "Authorization",
 75→                format!("Bearer {}", self.api_key.expose_secret()),
 76→            )
 77→            .header("content-type", "application/json")
 78→            .json(&body)
 79→            .send()
 80→            .await?;
 81→
 82→        let status = http_resp.status();
 83→        if !status.is_success() {
 84→            let retry_after_ms = retry_after_ms_from_headers(http_resp.headers());
 85→            let body_text = http_resp.text().await.unwrap_or_default();
 86→            if should_warn_on_api_error(status, &body_text) {
 87→                warn!(
 88→                    status = %status,
 89→                    model = %self.model,
 90→                    provider = %self.provider_name,
 91→                    body = %body_text,
 92→                    "openai probe API error"
 93→                );
 94→            } else {
 95→                debug!(
 96→                    status = %status,
 97→                    model = %self.model,
 98→                    provider = %self.provider_name,
 99→                    "openai probe model unsupported for chat/completions endpoint"
100→                );
101→            }
102→            // Ollama's OpenAI-compat layer returns 404 for models that
103→            // exist but aren't wired to /v1/chat/completions.  Fall back
104→            // to the native `/api/show` endpoint before giving up.
105→            if status == reqwest::StatusCode::NOT_FOUND
106→                && self.provider_name.eq_ignore_ascii_case("ollama")
107→            {
