307→    /// Non-streaming completion using the Responses API.
308→    ///
309→    /// Sends `stream: true` and collects events into a single response, since
310→    /// many Responses API endpoints only support streaming.
311→    pub(super) async fn complete_responses(
312→        &self,
313→        messages: &[ChatMessage],
314→        tools: &[serde_json::Value],
315→    ) -> anyhow::Result<CompletionResponse> {
316→        let (instructions, input) = split_responses_instructions_and_input(messages.to_vec());
317→        let mut body = serde_json::json!({
318→            "model": self.model,
319→            "input": input,
320→            "stream": true,
321→        });
322→        if let Some(instructions) = instructions {
323→            body["instructions"] = serde_json::Value::String(instructions);
324→        }
325→        if !tools.is_empty() {
326→            body["tools"] = serde_json::Value::Array(to_responses_api_tools(tools));
327→            body["tool_choice"] = serde_json::json!("auto");
328→        }
329→
330→        debug!(
331→            model = %self.model,
332→            messages_count = messages.len(),
333→            tools_count = tools.len(),
334→            "openai complete_responses request"
335→        );
336→        trace!(body = %serde_json::to_string(&body).unwrap_or_default(), "openai responses request body");
337→
338→        let url = self.responses_sse_url();
339→        let http_resp = self
340→            .client
341→            .post(&url)
342→            .header(
343→                "Authorization",
344→                format!("Bearer {}", self.api_key.expose_secret()),
345→            )
346→            .header("content-type", "application/json")
347→            .json(&body)
348→            .send()
349→            .await?;
350→
351→        let status = http_resp.status();
352→        if !status.is_success() {
353→            let retry_after_ms = retry_after_ms_from_headers(http_resp.headers());
354→            let body_text = http_resp.text().await.unwrap_or_default();
355→            anyhow::bail!(
356→                "{}",
357→                with_retry_after_marker(
358→                    format!("Responses API error HTTP {status}: {body_text}"),
359→                    retry_after_ms,
360→                )
361→            );
362→        }
363→
364→        // Collect SSE events into text + tool calls.
365→        let mut text_buf = String::new();
366→        let mut fn_call_ids: Vec<String> = Vec::new();
367→        let mut fn_call_names: Vec<String> = Vec::new();
368→        let mut fn_call_args: Vec<String> = Vec::new();
369→        let mut input_tokens: u32 = 0;
370→        let mut output_tokens: u32 = 0;
371→        let mut cache_read_tokens: u32 = 0;
372→        let cache_write_tokens: u32 = 0;
373→
374→        let full_body = http_resp.text().await.unwrap_or_default();
375→        for line in full_body.lines() {
376→            let line = line.trim();
377→            if line.is_empty() {
378→                continue;
379→            }
380→            let Some(data) = line
381→                .strip_prefix("data: ")
382→                .or_else(|| line.strip_prefix("data:"))
383→            else {
384→                continue;
385→            };
386→            if data == "[DONE]" {
387→                break;
388→            }
389→
390→            let Ok(evt) = serde_json::from_str::<serde_json::Value>(data) else {
391→                continue;
392→            };
393→
394→            match evt["type"].as_str().unwrap_or("") {
395→                "response.output_text.delta" => {
396→                    if let Some(delta) = evt["delta"].as_str() {
397→                        text_buf.push_str(delta);
398→                    }
399→                },
400→                "response.output_item.added" => {
401→                    if evt["item"]["type"].as_str() == Some("function_call") {
402→                        fn_call_ids.push(evt["item"]["call_id"].as_str().unwrap_or("").to_string());
403→                        fn_call_names.push(evt["item"]["name"].as_str().unwrap_or("").to_string());
404→                        fn_call_args.push(String::new());
405→                    }
406→                },
407→                "response.function_call_arguments.delta" => {
408→                    if let Some(delta) = evt["delta"].as_str()
409→                        && let Some(last) = fn_call_args.last_mut()
410→                    {
411→                        last.push_str(delta);
412→                    }
413→                },
414→                "response.completed" => {
415→                    if let Some(u) = evt["response"]["usage"].as_object() {
416→                        input_tokens =
417→                            u.get("input_tokens").and_then(|v| v.as_u64()).unwrap_or(0) as u32;
418→                        output_tokens =
419→                            u.get("output_tokens").and_then(|v| v.as_u64()).unwrap_or(0) as u32;
420→                        cache_read_tokens = u
421→                            .get("input_tokens_details")
422→                            .and_then(|d| d.get("cached_tokens"))
423→                            .and_then(|v| v.as_u64())
424→                            .unwrap_or(0) as u32;
425→                    }
426→                },
427→                "error" | "response.failed" => {
428→                    let msg = evt["error"]["message"]
429→                        .as_str()
430→                        .or_else(|| evt["response"]["error"]["message"].as_str())
431→                        .or_else(|| evt["message"].as_str())
432→                        .unwrap_or("unknown error");
433→                    anyhow::bail!("Responses API error: {msg}");
434→                },
435→                _ => {},
436→            }
437→        }
438→
439→        let text = if text_buf.is_empty() {
440→            None
441→        } else {
442→            Some(text_buf)
443→        };
444→
445→        let tool_calls: Vec<moltis_agents::model::ToolCall> = fn_call_ids
446→            .into_iter()
447→            .zip(fn_call_names)
448→            .zip(fn_call_args)
449→            .filter_map(|((id, name), args)| {
450→                let arguments: serde_json::Value = serde_json::from_str(&args)
451→                    .unwrap_or(serde_json::Value::Object(Default::default()));
452→                if name.is_empty() {
453→                    return None;
454→                }
455→                Some(moltis_agents::model::ToolCall {
456→                    id,
457→                    name,
458→                    arguments,
459→                })
460→            })
461→            .collect();
462→
463→        Ok(CompletionResponse {
464→            text,
465→            tool_calls,
466→            usage: Usage {
467→                input_tokens,
468→                output_tokens,
469→                cache_read_tokens,
470→                cache_write_tokens,
471→            },
472→        })
473→    }
474→}
