247→const OPENAI_MAX_TOOL_CALL_ID_LEN: usize = 40;
248→
249→fn short_stable_hash(value: &str) -> String {
250→    use std::hash::{Hash, Hasher};
251→
252→    let mut hasher = std::collections::hash_map::DefaultHasher::new();
253→    value.hash(&mut hasher);
254→    format!("{:016x}", hasher.finish())
255→}
256→
257→fn base_openai_tool_call_id(raw: &str) -> String {
258→    let mut cleaned: String = raw
259→        .chars()
260→        .map(|ch| {
261→            if ch.is_ascii_alphanumeric() || matches!(ch, '_' | '-') {
262→                ch
263→            } else {
264→                '_'
265→            }
266→        })
267→        .collect();
268→
269→    if cleaned.is_empty() {
270→        cleaned = "call".to_string();
271→    }
272→
273→    if cleaned.len() <= OPENAI_MAX_TOOL_CALL_ID_LEN {
274→        return cleaned;
275→    }
276→
277→    let hash = short_stable_hash(raw);
278→    let keep = OPENAI_MAX_TOOL_CALL_ID_LEN.saturating_sub(hash.len() + 1);
279→    cleaned.truncate(keep);
280→    if cleaned.is_empty() {
281→        return format!("call-{hash}");
282→    }
283→    format!("{cleaned}-{hash}")
284→}
285→
286→fn disambiguate_tool_call_id(base: &str, nonce: usize) -> String {
287→    let suffix = format!("-{nonce}");
288→    let keep = OPENAI_MAX_TOOL_CALL_ID_LEN.saturating_sub(suffix.len());
289→
290→    let mut value = base.to_string();
291→    if value.len() > keep {
292→        value.truncate(keep);
293→    }
294→    if value.is_empty() {
295→        value = "call".to_string();
296→        if value.len() > keep {
297→            value.truncate(keep);
298→        }
299→    }
300→    format!("{value}{suffix}")
301→}
302→
303→fn assign_openai_tool_call_id(
304→    raw: &str,
305→    remapped_tool_call_ids: &mut HashMap<String, String>,
306→    used_tool_call_ids: &mut HashSet<String>,
307→) -> String {
308→    if let Some(existing) = remapped_tool_call_ids.get(raw) {
309→        return existing.clone();
310→    }
311→
312→    let base = base_openai_tool_call_id(raw);
313→    let mut candidate = base.clone();
314→    let mut nonce = 1usize;
315→    while used_tool_call_ids.contains(&candidate) {
316→        candidate = disambiguate_tool_call_id(&base, nonce);
317→        nonce = nonce.saturating_add(1);
318→    }
319→
320→    used_tool_call_ids.insert(candidate.clone());
321→    remapped_tool_call_ids.insert(raw.to_string(), candidate.clone());
322→    candidate
323→}
