210→/// Convert tool schemas to OpenAI Chat Completions function-calling format.
211→///
212→/// Uses the nested `function` object format required by Chat Completions API:
213→/// ```json
214→/// { "type": "function", "function": { "name": "...", ... } }
215→/// ```
216→///
217→/// Adds `strict: true` and patches schemas for strict mode compliance:
218→/// - `additionalProperties: false` on all object schemas
219→/// - All properties included in `required` array
220→///
221→/// This is required by some APIs (Claude via Copilot) to ensure the model
222→/// provides all required fields.
223→///
224→/// See: <https://platform.openai.com/docs/guides/function-calling>
225→pub fn to_openai_tools(tools: &[serde_json::Value]) -> Vec<serde_json::Value> {
226→    let result: Vec<serde_json::Value> = tools
227→        .iter()
228→        .filter_map(|t| {
229→            // Clone parameters and patch for strict mode
230→            let mut params = t["parameters"].clone();
231→            sanitize_schema_for_openai_compat(&mut params);
232→            patch_schema_for_strict_mode(&mut params);
233→
234→            let name = t["name"].as_str()?.to_string();
235→            let description = t["description"].as_str().unwrap_or("").to_string();
236→
237→            // Use typed struct to ensure all required fields are present
238→            let tool = ChatCompletionsTool {
239→                tool_type: "function",
240→                function: ChatCompletionsFunction {
241→                    name: name.clone(),
242→                    description,
243→                    parameters: params,
244→                    strict: true,
245→                },
246→            };
247→
248→            trace!(tool_name = %name, "converted tool to Chat Completions format");
249→
250→            // Serialize to Value for compatibility with existing API
251→            serde_json::to_value(tool).ok()
252→        })
253→        .collect();
254→
255→    trace!(tools_count = result.len(), "to_openai_tools complete");
256→    result
257→}
258→
259→/// Convert tool schemas to OpenAI Responses API function-calling format.
260→///
261→/// Uses the flat format required by the Responses API where `name` is at top level:
262→/// ```json
263→/// { "type": "function", "name": "...", "parameters": {...}, "strict": true }
264→/// ```
265→///
266→/// This is the format used by OpenAI Codex and the Responses API.
267→///
268→/// Patches schemas for strict mode compliance:
269→/// - `additionalProperties: false` on all object schemas
270→/// - All properties included in `required` array
271→///
272→/// See: <https://learn.microsoft.com/en-us/azure/ai-foundry/openai/how-to/responses>
273→pub fn to_responses_api_tools(tools: &[serde_json::Value]) -> Vec<serde_json::Value> {
274→    let result: Vec<serde_json::Value> = tools
275→        .iter()
276→        .filter_map(|t| {
277→            // Clone parameters and patch for strict mode
278→            let mut params = t["parameters"].clone();
279→            sanitize_schema_for_openai_compat(&mut params);
280→            patch_schema_for_strict_mode(&mut params);
281→
282→            let name = t["name"].as_str()?.to_string();
