    {
        match process_responses_sse_line(data, &mut state) {
            SseLineResult::Done => {
                extend_events_or_error(&mut events, finalize_responses_stream(&mut state))?;
                return Ok(stream_events_to_completion(events));
            },
            SseLineResult::Events(new_events) => {
