/// Google model for testing non-strict tool schemas.
/// Uses a free model to avoid costs in CI.
const GOOGLE_TEST_MODEL: &str = "google/gemma-4-31b-it:free";

/// Complex tool schema modeled after the cron tool: nested objects, optional
/// booleans, enum fields — the shapes that trigger Google's INVALID_ARGUMENT
/// when strict-mode array types are present.
fn complex_cron_like_tool() -> serde_json::Value {
    serde_json::json!({
        "name": "schedule_cron",
        "description": "Schedule a cron job. You MUST call this tool when asked to schedule something.",
        "parameters": {
            "type": "object",
            "properties": {
                "name": { "type": "string", "description": "Job name" },
                "job": {
                    "type": "object",
                    "properties": {
                        "enabled": { "type": "boolean", "description": "Whether the job is enabled" },
                        "schedule": { "type": "string", "description": "Cron expression" },
                        "retry": { "type": "boolean", "description": "Retry on failure" },
                        "mode": {
                            "type": "string",
                            "enum": ["once", "recurring"],
                            "description": "Execution mode"
                        },
                        "config": {
                            "type": "object",
                            "properties": {
                                "timeout": { "type": "integer", "description": "Timeout in seconds" },
                                "verbose": { "type": "boolean", "description": "Enable verbose logging" }
                            },
                            "required": ["timeout"]
                        }
                    },
                    "required": ["schedule"]
                }
            },
            "required": ["name", "job"]
        }
    })
}

#[tokio::test]
#[ignore]
async fn tool_call_google_model_non_streaming() {
