fn to_openai_tools_non_strict_skips_patching() {
    let tools = vec![serde_json::json!({
        "name": "create_file",
        "description": "Create a file",
        "parameters": {
            "type": "object",
            "properties": {
                "path": { "type": "string" },
                "content": { "type": "string" },
                "overwrite": { "type": "boolean" }
            },
            "required": ["path"]
        }
    })];

    let converted = to_openai_tools(&tools, false);
    assert_eq!(converted.len(), 1);

    let func = &converted[0]["function"];
    assert_eq!(func["strict"], false);

    // Original required array is preserved — only "path".
    let required = func["parameters"]["required"]
        .as_array()
        .expect("required array");
    assert_eq!(required.len(), 1);
    assert_eq!(required[0], "path");

    // No additionalProperties injected.
    assert!(func["parameters"].get("additionalProperties").is_none());

    // Types remain in simple string form, not array form.
    assert_eq!(func["parameters"]["properties"]["overwrite"]["type"], "boolean");
    assert_eq!(func["parameters"]["properties"]["content"]["type"], "string");
}

