                "tuple": {
                    "type": "array",
                    "items": [
                        {
                            "type": "string",
                            "not": { "const": "" }
                        },
                        {
                            "type": "object",
                            "patternProperties": {
                                "^x-": { "type": "string" }
                            }
                        }
                    ]
                }
            }
        });

        sanitize_schema_for_openai_compat(&mut schema);

        let Some(tuple_items) = schema["properties"]["tuple"]["items"].as_array() else {
