112→/// Recursively patch schema for OpenAI strict mode compliance.
113→///
114→/// OpenAI's strict mode requires:
115→/// 1. `additionalProperties: false` on every object in the schema tree
116→/// 2. All properties must be listed in the `required` array
117→///
118→/// Properties not in the original `required` array are made nullable so the
119→/// model can send `null` for unused optional fields instead of fabricating
120→/// placeholder values.
121→///
122→/// This function recursively patches nested objects in `properties`, array
123→/// `items`, `anyOf`/`oneOf`/`allOf` variants, etc.
124→pub fn patch_schema_for_strict_mode(schema: &mut serde_json::Value) {
125→    let Some(obj) = schema.as_object_mut() else {
126→        return;
127→    };
128→
129→    // Collect originally-optional property names so we can make them nullable
130→    // AFTER recursion (otherwise changing "type":"object" to ["object","null"]
131→    // would prevent the recursive pass from recognising nested objects).
132→    let mut optional_props: Vec<String> = Vec::new();
133→
134→    // If this is an object type, apply strict mode requirements
135→    if obj.get("type").and_then(|t| t.as_str()) == Some("object") {
136→        // Add additionalProperties: false
137→        obj.insert("additionalProperties".to_string(), serde_json::json!(false));
138→
139→        // Ensure all properties are in required array.
140→        if let Some(props) = obj.get("properties").and_then(|p| p.as_object()).cloned() {
141→            let originally_required: HashSet<String> = obj
142→                .get("required")
143→                .and_then(|r| r.as_array())
144→                .map(|arr| {
145→                    arr.iter()
146→                        .filter_map(|v| v.as_str().map(String::from))
147→                        .collect()
148→                })
149→                .unwrap_or_default();
150→
151→            let all_prop_names: Vec<serde_json::Value> =
152→                props.keys().map(|k| serde_json::json!(k)).collect();
153→            obj.insert("required".to_string(), serde_json::json!(all_prop_names));
154→
155→            // Remember which properties need to be made nullable (deferred).
156→            for key in props.keys() {
157→                if !originally_required.contains(key) {
158→                    optional_props.push(key.clone());
159→                }
160→            }
161→        } else {
162→            // Object without properties - add empty properties and required
163→            obj.insert("properties".to_string(), serde_json::json!({}));
164→            obj.insert("required".to_string(), serde_json::json!([]));
165→        }
166→    }
167→
168→    // Recurse into properties
169→    if let Some(props) = obj.get_mut("properties").and_then(|p| p.as_object_mut()) {
170→        for (_, prop_schema) in props.iter_mut() {
171→            patch_schema_for_strict_mode(prop_schema);
172→        }
173→    }
174→
175→    // Recurse into array items
176→    if let Some(items) = obj.get_mut("items") {
177→        patch_schema_for_strict_mode(items);
178→    }
179→
180→    // Recurse into anyOf/oneOf/allOf
181→    for key in ["anyOf", "oneOf", "allOf"] {
182→        if let Some(variants) = obj.get_mut(key).and_then(|v| v.as_array_mut()) {
183→            for variant in variants {
184→                patch_schema_for_strict_mode(variant);
185→            }
186→        }
187→    }
188→
189→    // Recurse into additionalProperties if it's a schema (not just true/false)
190→    if let Some(additional) = obj.get_mut("additionalProperties")
191→        && additional.is_object()
192→    {
193→        patch_schema_for_strict_mode(additional);
194→    }
195→
196→    // Now that recursion is done, make originally-optional properties nullable
197→    // so the model can send `null` instead of fabricating placeholder values
198→    // (e.g. empty strings) that downstream MCP servers reject.
199→    if !optional_props.is_empty()
200→        && let Some(props) = obj.get_mut("properties").and_then(|p| p.as_object_mut())

200→        && let Some(props) = obj.get_mut("properties").and_then(|p| p.as_object_mut())
201→    {
202→        for key in &optional_props {
203→            if let Some(prop_schema) = props.get_mut(key) {
204→                make_nullable(prop_schema);
205→            }
206→        }
207→    }
208→}
