210→/// Convert tool schemas to OpenAI Chat Completions function-calling format.
211→///
212→/// Uses the nested `function` object format required by Chat Completions API:
213→/// ```json
214→/// { "type": "function", "function": { "name": "...", ... } }
215→/// ```
216→///
217→/// When `strict` is `true`, patches schemas for strict mode compliance:
218→/// - `additionalProperties: false` on all object schemas
219→/// - All properties included in `required` array
220→/// - Originally-optional properties made nullable via array-form types
221→///
222→/// When `strict` is `false`, schemas are sanitized but not patched for strict
223→/// mode. This avoids array-form types like `["boolean", "null"]` that
224→/// non-OpenAI backends (e.g. Google via OpenRouter) reject.
225→///
226→/// See: <https://platform.openai.com/docs/guides/function-calling>
227→pub fn to_openai_tools(tools: &[serde_json::Value], strict: bool) -> Vec<serde_json::Value> {
228→    let result: Vec<serde_json::Value> = tools
229→        .iter()
230→        .filter_map(|t| {
231→            let mut params = t["parameters"].clone();
232→            sanitize_schema_for_openai_compat(&mut params);
233→            if strict {
234→                patch_schema_for_strict_mode(&mut params);
235→            }
236→
237→            let name = t["name"].as_str()?.to_string();
238→            let description = t["description"].as_str().unwrap_or("").to_string();
239→
240→            // Use typed struct to ensure all required fields are present
241→            let tool = ChatCompletionsTool {
242→                tool_type: "function",
243→                function: ChatCompletionsFunction {
244→                    name: name.clone(),
245→                    description,
246→                    parameters: params,
247→                    strict,
248→                },
249→            };
250→
251→            trace!(tool_name = %name, strict, "converted tool to Chat Completions format");
252→
253→            // Serialize to Value for compatibility with existing API
254→            serde_json::to_value(tool).ok()
255→        })
256→        .collect();
257→
258→    trace!(tools_count = result.len(), "to_openai_tools complete");
259→    result
260→}
