275→/// See: <https://learn.microsoft.com/en-us/azure/ai-foundry/openai/how-to/responses>
276→pub fn to_responses_api_tools(tools: &[serde_json::Value]) -> Vec<serde_json::Value> {
277→    let result: Vec<serde_json::Value> = tools
278→        .iter()
279→        .filter_map(|t| {
280→            // Clone parameters and patch for strict mode
281→            let mut params = t["parameters"].clone();
282→            sanitize_schema_for_openai_compat(&mut params);
283→            patch_schema_for_strict_mode(&mut params);
284→
285→            let name = t["name"].as_str()?.to_string();
286→            let description = t["description"].as_str().unwrap_or("").to_string();
287→
288→            // Use typed struct to ensure all required fields are present
289→            let tool = ResponsesApiTool {
290→                tool_type: "function",
291→                name: name.clone(),
292→                description,
293→                parameters: params,
294→                strict: true,
295→            };
296→
297→            trace!(tool_name = %name, "converted tool to Responses API format");
298→
299→            // Serialize to Value for compatibility with existing API
300→            serde_json::to_value(tool).ok()
301→        })
302→        .collect();
303→
304→    trace!(
305→        tools_count = result.len(),
306→        "to_responses_api_tools complete"
307→    );
308→    result
