311→/// Convert typed chat messages to Responses API input items.
312→///
313→/// Responses API accepts a heterogeneous input array (messages, tool calls, and
314→/// tool outputs). This keeps one canonical conversion for providers that use
315→/// Responses transport (SSE or WebSocket).
316→#[must_use]
317→pub fn to_responses_input(messages: &[ChatMessage]) -> Vec<serde_json::Value> {
318→    messages
319→        .iter()
320→        .flat_map(|msg| match msg {
321→            ChatMessage::System { .. } => {
322→                // System messages are extracted into `instructions`.
323→                vec![]
324→            },
325→            ChatMessage::User { content } => {
326→                let content_blocks = match content {
327→                    UserContent::Text(t) => {
328→                        vec![serde_json::json!({"type": "input_text", "text": t})]
329→                    },
330→                    UserContent::Multimodal(parts) => parts
331→                        .iter()
332→                        .map(|p| match p {
333→                            moltis_agents::model::ContentPart::Text(t) => {
334→                                serde_json::json!({"type": "input_text", "text": t})
335→                            },
336→                            moltis_agents::model::ContentPart::Image { media_type, data } => {
337→                                let data_uri = format!("data:{media_type};base64,{data}");
338→                                serde_json::json!({
339→                                    "type": "input_image",
340→                                    "image_url": data_uri,
341→                                })
342→                            },
343→                        })
344→                        .collect(),
345→                };
346→                vec![serde_json::json!({
347→                    "role": "user",
348→                    "content": content_blocks,
349→                })]
350→            },
351→            ChatMessage::Assistant {
352→                content,
353→                tool_calls,
354→            } => {
355→                if !tool_calls.is_empty() {
356→                    let mut items: Vec<serde_json::Value> = tool_calls
357→                        .iter()
358→                        .map(|tc| {
359→                            serde_json::json!({
360→                                "type": "function_call",
361→                                "call_id": tc.id,
362→                                "name": tc.name,
363→                                "arguments": tc.arguments.to_string(),
364→                            })
365→                        })
366→                        .collect();
367→                    if let Some(text) = content
368→                        && !text.is_empty()
369→                    {
370→                        items.insert(
371→                            0,
372→                            serde_json::json!({
373→                                "type": "message",
374→                                "role": "assistant",
375→                                "content": [{"type": "output_text", "text": text}]
376→                            }),
377→                        );
378→                    }
379→                    items
380→                } else {
381→                    let text = content.as_deref().unwrap_or("");
382→                    vec![serde_json::json!({
383→                        "type": "message",
384→                        "role": "assistant",
385→                        "content": [{"type": "output_text", "text": text}]
386→                    })]
387→                }
388→            },
389→            ChatMessage::Tool {
390→                tool_call_id,
391→                content,
392→            } => {
393→                vec![serde_json::json!({
394→                    "type": "function_call_output",
395→                    "call_id": tool_call_id,
396→                    "output": content,
397→                })]
398→            },
399→        })
400→        .collect()
401→}
