458→        .and_then(serde_json::Value::as_array)
459→        .and_then(|choices| choices.first())
460→        .and_then(|choice| choice.get("delta"))
461→        .and_then(|delta| delta.get("usage"))
462→        .filter(|usage| usage.is_object())
463→    {
464→        return Some(usage);
465→    }
466→
467→    if let Some(usage) = payload
468→        .get("choices")
469→        .and_then(serde_json::Value::as_array)
470→        .and_then(|choices| choices.first())
471→        .and_then(|choice| choice.get("message"))
472→        .and_then(|message| message.get("usage"))
473→        .filter(|usage| usage.is_object())
