 63→fn title_case_chunk(chunk: &str) -> String {
 64→    if chunk.is_empty() {
 65→        return String::new();
 66→    }
 67→    let mut chars = chunk.chars();
 68→    match chars.next() {
 69→        Some(first) => {
 70→            let mut out = String::new();
 71→            out.push(first.to_ascii_uppercase());
 72→            out.push_str(chars.as_str());
 73→            out
 74→        },
 75→        None => String::new(),
 76→    }
 77→}
