 79→fn format_gpt_display_name(model_id: &str) -> String {
 80→    let Some(rest) = model_id.strip_prefix("gpt-") else {
 81→        return model_id.to_string();
 82→    };
 83→    let mut parts = rest.split('-');
 84→    let Some(base) = parts.next() else {
 85→        return "GPT".to_string();
 86→    };
 87→    let mut out = format!("GPT-{base}");
 88→    for part in parts {
 89→        out.push(' ');
 90→        out.push_str(&title_case_chunk(part));
 91→    }
 92→    out
 93→}
