 63→                        "type": "text",
 64→                        "text": text,
 65→                        "cache_control": cache_control
 66→                    }]);
 67→                },
 68→                Some(content) if content.is_array() => {
 69→                    if let Some(last) = content.as_array_mut().and_then(|a| a.last_mut()) {
