pub(super) fn build_schema_map() -> KnownKeys {
    use KnownKeys::{Array, Leaf, Map, MapWithFields, Struct};

    let tool_policy_entry = || {
        Struct(HashMap::from([
            ("allow", Leaf),
            ("deny", Leaf),
            ("profile", Leaf),
        ]))
    };

    let provider_entry = || {
        Struct(HashMap::from([
            ("enabled", Leaf),
            ("api_key", Leaf),
            ("base_url", Leaf),
            ("url", Leaf),
            ("models", Leaf),
            ("fetch_models", Leaf),
            ("stream_transport", Leaf),
            ("wire_api", Leaf),
            ("alias", Leaf),
            ("tool_mode", Leaf),
            ("cache_retention", Leaf),
            ("policy", tool_policy_entry()),
        ]))
    };

    let resource_limits = || {
        Struct(HashMap::from([
