157→/// Helper for schema drift guard: recursively collect keys in `value` that
158→/// are not present in `schema`.
159→fn collect_missing_keys(
160→    value: &toml::Value,
161→    schema: &KnownKeys,
162→    prefix: &str,
163→    missing: &mut Vec<String>,
164→) {
165→    match (value, schema) {
166→        (toml::Value::Table(table), KnownKeys::Struct(fields)) => {
167→            for (key, child_value) in table {
168→                let path = if prefix.is_empty() {
169→                    key.clone()
170→                } else {
171→                    format!("{prefix}.{key}")
172→                };
173→                if let Some(child_schema) = fields.get(key.as_str()) {
174→                    collect_missing_keys(child_value, child_schema, &path, missing);
175→                } else {
176→                    missing.push(path);
177→                }
178→            }
179→        },
180→        (toml::Value::Table(table), KnownKeys::Map(value_schema)) => {
181→            for (key, child_value) in table {
182→                let path = if prefix.is_empty() {
183→                    key.clone()
184→                } else {
185→                    format!("{prefix}.{key}")
186→                };
187→                collect_missing_keys(child_value, value_schema, &path, missing);
188→            }
189→        },
190→        (
191→            toml::Value::Table(table),
192→            KnownKeys::MapWithFields {
193→                value: value_schema,
194→                fields,
195→            },
196→        ) => {
197→            for (key, child_value) in table {
198→                let path = if prefix.is_empty() {
199→                    key.clone()
200→                } else {
201→                    format!("{prefix}.{key}")
202→                };
203→                if let Some(child_schema) = fields.get(key.as_str()) {
