 58→fn canonicalize_schema_for_openai_compat(schema: &serde_json::Value) -> serde_json::Value {
 59→    let document = match SchemaDocument::from_json(schema) {
 60→        Ok(document) => document,
 61→        Err(error) => {
 62→            warn!(
 63→                error = %error,
 64→                "openai tool schema failed Draft 2020-12 preflight; using raw schema for best-effort normalization"
 65→            );
 66→            return schema.clone();
 67→        },
 68→    };
 69→
 70→    if let Err(error) = document.root() {
 71→        warn!(
 72→            error = %error,
 73→            "openai tool schema failed canonical AST resolution; using raw schema for best-effort normalization"
 74→        );
 75→        return schema.clone();
 76→    }
 77→
 78→    document
 79→        .canonical_schema_json()
 80→        .map_or_else(
 81→            |error| {
 82→                warn!(
 83→                    error = %error,
 84→                    "openai tool schema canonicalization was unavailable; using raw schema for best-effort normalization"
 85→                );
 86→                schema.clone()
 87→            },
 88→            serde_json::Value::clone,
 89→        )
 90→}
