 53→                tm.field, tm.expected, tm.actual,
 54→            ));
 55→        }
 56→
 57→        let received_str = serde_json::to_string(&self.received)
 58→            .unwrap_or_else(|_| "<unserializable>".to_string());
 59→        msg.push_str(&format!("You sent: {received_str}\n"));
 60→        msg.push_str(
 61→            "Do not retry with the same arguments. If you do not know what arguments to use, \
 62→             respond in plain text and ask the user for clarification.",
 63→        );
 64→        msg
 65→    }
 66→
 67→    /// Short single-line description for logs and metrics.
 68→    #[must_use]
 69→    pub fn short_summary(&self) -> String {
 70→        let mut parts = Vec::new();
 71→        if !self.missing_required.is_empty() {
 72→            parts.push(format!("missing={}", self.missing_required.join(",")));
 73→        }
 74→        if !self.type_mismatches.is_empty() {
 75→            let tm: Vec<String> = self
 76→                .type_mismatches
 77→                .iter()
 78→                .map(|t| format!("{}:{}!={}", t.field, t.expected, t.actual))
 79→                .collect();
 80→            parts.push(format!("type_mismatch={}", tm.join(",")));
 81→        }
 82→        parts.join(" ")
 83→    }
 84→}
