 86→/// Validate `args` against `schema`.
 87→///
 88→/// Returns `Ok(())` when the schema imposes no checkable constraints or all
 89→/// constraints pass. Returns `Err(ToolArgError)` on the narrow failure class
 90→/// this validator targets.
 91→///
 92→/// # Errors
 93→/// Returns [`ToolArgError`] when required fields are missing or top-level
 94→/// types do not match the schema's declared `properties.<field>.type`.
 95→pub fn validate_tool_args(schema: &Value, args: &Value) -> Result<(), ToolArgError> {
 96→    // Only object schemas have required/properties we can check.
 97→    let Some(schema_obj) = schema.as_object() else {
 98→        return Ok(());
 99→    };
100→
101→    // Empty schema: pass.
102→    if schema_obj.is_empty() {
103→        return Ok(());
104→    }
105→
106→    // If no required array AND no properties to type-check, pass.
107→    let required_list: Vec<String> = schema_obj
108→        .get("required")
109→        .and_then(Value::as_array)
110→        .map(|arr| {
111→            arr.iter()
112→                .filter_map(|v| v.as_str().map(String::from))
113→                .collect()
114→        })
115→        .unwrap_or_default();
116→
117→    let properties = schema_obj.get("properties").and_then(Value::as_object);
118→
119→    if required_list.is_empty() && properties.is_none() {
120→        return Ok(());
121→    }
122→
123→    // Args must be an object to satisfy any required field.
124→    let args_obj = match args.as_object() {
125→        Some(obj) => obj,
126→        None => {
127→            // Non-object args with required fields → all missing.
128→            if required_list.is_empty() {
129→                return Ok(());
130→            }
131→            return Err(ToolArgError {
132→                missing_required: required_list,
133→                type_mismatches: Vec::new(),
134→                received: args.clone(),
135→            });
136→        },
137→    };
138→
139→    let mut missing_required = Vec::new();
140→    for field in &required_list {
141→        match args_obj.get(field) {
142→            None => missing_required.push(field.clone()),
143→            Some(Value::Null) => missing_required.push(field.clone()),
144→            Some(_) => {},
145→        }
146→    }
147→
148→    let mut type_mismatches = Vec::new();
149→    if let Some(props) = properties {
150→        for (field, prop_schema) in props {
151→            let Some(actual_val) = args_obj.get(field) else {
152→                continue; // Missing-required is handled above; optional missing is fine.
153→            };
154→            if actual_val.is_null() {
155→                continue;
156→            }
157→            let Some(expected_type) = prop_schema.as_object().and_then(|o| o.get("type")) else {
158→                continue; // No declared type → nothing to check.
159→            };
160→            let actual_type = value_type_name(actual_val);
161→            if !type_matches(expected_type, actual_val) {
162→                type_mismatches.push(TypeMismatch {
163→                    field: field.clone(),
164→                    expected: expected_type_name(expected_type),
165→                    actual: actual_type.to_string(),
166→                });
167→            }
168→        }
169→    }
170→
171→    if missing_required.is_empty() && type_mismatches.is_empty() {
172→        return Ok(());
173→    }
174→
175→    Err(ToolArgError {
176→        missing_required,
177→        type_mismatches,
178→        received: args.clone(),
179→    })
180→}
181→
182→fn type_matches(expected: &Value, value: &Value) -> bool {
183→    match expected {
184→        Value::String(expected) => type_matches_single(expected, value),
185→        Value::Array(expected_types) => expected_types
186→            .iter()
187→            .filter_map(Value::as_str)
188→            .any(|expected| type_matches_single(expected, value)),
189→        _ => true,
190→    }
191→}
192→
193→fn type_matches_single(expected: &str, value: &Value) -> bool {
194→    match expected {
195→        "string" => value.is_string(),
196→        "number" => value.is_number(),
197→        // Some LLMs serialize integers with a trailing decimal (e.g.
198→        // `"timeout": 30.0`). Accept integer-valued floats to avoid spurious
199→        // rejections that would contribute to loop-detector churn rather than
200→        // catching real reflex loops.
201→        "integer" => {
202→            value.as_i64().is_some()
203→                || value.as_u64().is_some()
204→                || value.as_f64().is_some_and(|f| f.fract() == 0.0)
205→        },
206→        "boolean" => value.is_boolean(),
207→        "object" => value.is_object(),
208→        "array" => value.is_array(),
209→        "null" => value.is_null(),
210→        // Unknown/complex types (unions, $ref, etc.): don't claim a mismatch.
211→        _ => true,
212→    }
213→}
214→
215→fn expected_type_name(expected: &Value) -> String {
216→    match expected {
217→        Value::String(single) => single.clone(),
218→        Value::Array(types) => {
219→            let labels: Vec<&str> = types.iter().filter_map(Value::as_str).collect();
220→            if labels.is_empty() {
221→                "unknown".to_string()
222→            } else {
223→                labels.join(" | ")
224→            }
225→        },
226→        _ => "unknown".to_string(),
227→    }
228→}
229→
230→fn value_type_name(value: &Value) -> &'static str {
231→    match value {
232→        Value::Null => "null",
233→        Value::Bool(_) => "boolean",
234→        Value::Number(_) => "number",
235→        Value::String(_) => "string",
236→        Value::Array(_) => "array",
237→        Value::Object(_) => "object",
238→    }
239→}
